(199, 1, '2026-04-10 19:05:53', '2026-04-10 16:05:53', '<img class=\"aligncenter size-full wp-image-391\" src=\"http://localhost/node.js/wp-content/uploads/2026/04/Gemini_Generated_Image_sul960sul960sul9.png\" alt=\"\" width=\"2816\" height=\"1536\" />\r\n\r\nMiddleware bir <strong>ara yazılımdır</strong>. İstekleri ve yanıtları yönetir. Middleware katmanı, genellikle tüm route rotalarında yapılacak işlemleri tek elden yönetmek için kullanılmaktadır.\r\n\r\nMiddleware ile teknik bir boyutta ilgilenecek olursak;\r\n<div class=\"line number1 index0 alt2\"><code class=\"jscript plain\">const express = require(</code><code class=\"jscript string\">\"express\"</code><code class=\"jscript plain\">);</code></div>\r\n<div class=\"line number2 index1 alt1\"><code class=\"jscript plain\">const app = express();</code></div>\r\n<div class=\"line number3 index2 alt2\"></div>\r\n<div class=\"line number4 index3 alt1\"><code class=\"jscript plain\">app.use((request, response, next) =&gt; {</code></div>\r\n<div class=\"line number5 index4 alt2\"><code class=\"jscript spaces\">    </code><code class=\"jscript plain\">response.send(</code><code class=\"jscript string\">\"Middleware çalıştı.\"</code><code class=\"jscript plain\">);</code></div>\r\n<div class=\"line number6 index5 alt1\"><code class=\"jscript plain\">});</code></div>\r\n<div class=\"line number7 index6 alt2\"></div>\r\n<div class=\"line number8 index7 alt1\"><code class=\"jscript plain\">app.get(</code><code class=\"jscript string\">\"/\"</code><code class=\"jscript plain\">, (request, response) =&gt; {</code></div>\r\n<div class=\"line number9 index8 alt2\"><code class=\"jscript spaces\">    </code><code class=\"jscript plain\">response.send(</code><code class=\"jscript string\">\"Route çalıştı...\"</code><code class=\"jscript plain\">);</code></div>\r\n<div class=\"line number10 index9 alt1\"><code class=\"jscript plain\">}).listen(5000);</code></div>\r\n<div></div>\r\n<div>Yukarıdaki kod bloğunda <strong>app.use</strong> fonksiyonundaki callback ile Midleware oluşturuyoruz. Bu işlem sonrasında <strong>app</strong> üzerinden oluşturulan tüm <strong>route yapıları</strong> için herhangi bir istek söz konusu olursa bu istek karşılığında cevap verilmeden önce ilgili <strong>middleware</strong> devreye girecektir.</div>\r\n<div></div>\r\n<div>Şöyle ki bu kodu çalıştırdığınız an <strong>route</strong> çalışmayacaktır çünkü nedeni <strong>next</strong> fonksiyonu çağrılmadığından dolayıdır.</div>\r\n<div></div>\r\n<div>Şimdi ise <strong>next</strong> fonksiyonunu inceleyelim.  Bu fonksiyon çağrıldığı zaman ilgili middleware’de ki çalışmaların onaylandığı bir başka deyişle doğrulandığı söz konusu olacaktır ve middleware tetiklenmeden önce hangi route’a istek gönderildiyse o <strong>route</strong> bu doğrulama neticesinde çalıştırılacaktır.</div>\r\n<div></div>\r\n<div>Next fonksiyonunu çağırdığımız durumda ise;</div>\r\n<div>\r\n<div class=\"line number1 index0 alt2\"><code class=\"jscript plain\">const express = require(</code><code class=\"jscript string\">\"express\"</code><code class=\"jscript plain\">);</code></div>\r\n<div class=\"line number2 index1 alt1\"><code class=\"jscript plain\">const app = express();</code></div>\r\n<div class=\"line number3 index2 alt2\"></div>\r\n<div class=\"line number4 index3 alt1\"><code class=\"jscript plain\">app.use((request, response, next) =&gt; {</code></div>\r\n<div class=\"line number5 index4 alt2\"><code class=\"jscript spaces\">    </code><code class=\"jscript plain\">next();</code></div>\r\n<div class=\"line number6 index5 alt1\"><code class=\"jscript plain\">});</code></div>\r\n<div class=\"line number7 index6 alt2\"></div>\r\n<div class=\"line number8 index7 alt1\"><code class=\"jscript plain\">app.get(</code><code class=\"jscript string\">\"/\"</code><code class=\"jscript plain\">, (request, response) =&gt; {</code></div>\r\n<div class=\"line number9 index8 alt2\"><code class=\"jscript spaces\">    </code><code class=\"jscript plain\">response.send(</code><code class=\"jscript string\">\"Route çalıştı...\"</code><code class=\"jscript plain\">);</code></div>\r\n<div class=\"line number10 index9 alt1\"><code class=\"jscript plain\">}).listen(5000);</code></div>\r\n<div><strong>\"Route çalıştı...\"</strong> çıktısını görebileceğiz. Çünkü <strong>next</strong> fonksiyonu çağrıldı. Bu şekilde “next” fonksiyonunu tetiklersek direkt olarak route tetiklenecektir. Middleware ile kullanıcı oturum kontrolü sağlanabilecek bir uygulama yapılabilir. Ayrıca kayıt tutma, güvenlik kontrolü için de fayda sağlar.</div>\r\n</div>', 'Middleware (Ara Yazılım) Mantığı', '', 'publish', 'closed', 'open', '', 'middleware-ara-yazilim-mantigi', '', '', '2026-05-07 00:30:08', '2026-05-06 21:30:08', '', 0, 'http://localhost/node.js/?p=199', 0, 'post', '', 0),
